import{_ as s,o as a,c as i,a2 as t}from"./chunks/framework.DSLFjWWy.js";const u=JSON.parse('{"title":"Install the Plugin","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/install-the-plugin.md","filePath":"how-to/install-the-plugin.md","lastUpdated":1781555145000}'),n={name:"how-to/install-the-plugin.md"};function l(o,e,h,r,p,d){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="install-the-plugin" tabindex="-1">Install the Plugin <a class="header-anchor" href="#install-the-plugin" aria-label="Permalink to &quot;Install the Plugin&quot;">​</a></h1><p>Build AOSC for the OpenSearch version you run, then install the ZIP on every cluster node.</p><h2 id="supported-versions" tabindex="-1">Supported Versions <a class="header-anchor" href="#supported-versions" aria-label="Permalink to &quot;Supported Versions&quot;">​</a></h2><p>The build currently declares support for:</p><ul><li>OpenSearch <code>2.15.0</code></li><li>OpenSearch <code>2.17.0</code></li><li>OpenSearch <code>2.19.0</code></li></ul><p>Patch releases within the same minor may be compatible because the plugin descriptor is rewritten to a <code>~X.Y.Z</code> semver range. Test the exact OpenSearch version before using it. See <a href="./../reference/compatibility">Compatibility</a> for the current build and test matrix.</p><h2 id="build-from-source" tabindex="-1">Build from Source <a class="header-anchor" href="#build-from-source" aria-label="Permalink to &quot;Build from Source&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/atlassian-labs/opensearch-aosc.git</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensearch-aosc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :aosc-plugin:assemble</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -Dopensearch.version=2.19.0</span></span></code></pre></div><p>Output:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>aosc-plugin/build/distributions/opensearch-aosc-&lt;version&gt;.zip</span></span></code></pre></div><p>Repeat the build command with a different <code>-Dopensearch.version=...</code> when you need a ZIP for another supported OpenSearch minor.</p><h2 id="install-from-github-release" tabindex="-1">Install from GitHub Release <a class="header-anchor" href="#install-from-github-release" aria-label="Permalink to &quot;Install from GitHub Release&quot;">​</a></h2><p>Published releases attach one ZIP per supported OpenSearch minor:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensearch-aosc-&lt;aosc-version&gt;-opensearch-&lt;opensearch-minor&gt;.zip</span></span></code></pre></div><p>For example, an AOSC <code>0.1.0</code> release for OpenSearch <code>2.19.x</code> uses:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>opensearch-aosc-0.1.0-opensearch-2.19.zip</span></span></code></pre></div><p>Download the ZIP matching your OpenSearch minor, verify it against <code>SHA256SUMS</code>, then install that ZIP on each node.</p><h2 id="install-on-each-node" tabindex="-1">Install on Each Node <a class="header-anchor" href="#install-on-each-node" aria-label="Permalink to &quot;Install on Each Node&quot;">​</a></h2><p>Install the plugin on every cluster-manager and data node. Installing it on all nodes is the safest default because transport actions and services are registered by the plugin.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$OPENSEARCH_HOME/bin/opensearch-plugin install file:///path/to/opensearch-aosc-</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">version</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.zip</span></span></code></pre></div><p>Check node roles:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://localhost:9200/_cat/nodes?v&amp;h=name,node.role&#39;</span></span></code></pre></div><p>Restart nodes one at a time according to your OpenSearch operating procedure.</p><h2 id="verify-installation" tabindex="-1">Verify Installation <a class="header-anchor" href="#verify-installation" aria-label="Permalink to &quot;Verify Installation&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:9200/_cat/plugins?v</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensearch-aosc</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:9200/_plugins/_aosc/_list</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.&#39;</span></span></code></pre></div><p>A cluster with no migrations returns an empty <code>migrations</code> array.</p><h2 id="common-problems" tabindex="-1">Common Problems <a class="header-anchor" href="#common-problems" aria-label="Permalink to &quot;Common Problems&quot;">​</a></h2><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Symptom</th><th>Check</th></tr></thead><tbody><tr><td>Plugin version mismatch</td><td>Run <code>_cat/plugins</code> on all nodes and reinstall the same ZIP everywhere.</td></tr><tr><td><code>opensearch.version</code> build error</td><td>Pass <code>-Dopensearch.version=...</code> or export <code>OPENSEARCH_VERSION</code>.</td></tr><tr><td>Plugin does not load</td><td>Check OpenSearch logs for version mismatch, permissions, or dependency errors.</td></tr><tr><td>REST action missing</td><td>Confirm every relevant node has the plugin installed and was restarted.</td></tr></tbody></table></div>`,28)])])}const k=s(n,[["render",l]]);export{u as __pageData,k as default};
